export const PHASE1_AI_GATE = 50;

export const WEIGHTS = {
  titleRelevance: 25,
  skillsMatch: 25,
  experienceMatch: 20,
  locationMatch: 15,
  industryMatch: 15,
} as const;

export interface JobMatchInput {
  titleRelevance: number;
  skillsMatch: number;
  experienceMatch: number;
  locationMatch: number;
  industryMatch: number;
}

export function computeAlgorithmicScore(input: JobMatchInput): number {
  const total =
    (input.titleRelevance * WEIGHTS.titleRelevance +
      input.skillsMatch * WEIGHTS.skillsMatch +
      input.experienceMatch * WEIGHTS.experienceMatch +
      input.locationMatch * WEIGHTS.locationMatch +
      input.industryMatch * WEIGHTS.industryMatch) /
    100;

  return Math.round(total * 100) / 100;
}

export function passesPhase1Gate(score: number): boolean {
  return score >= PHASE1_AI_GATE;
}

import { describe, expect, test } from "bun:test";
import {
  PHASE1_AI_GATE,
  WEIGHTS,
  passesPhase1Gate,
  computeAlgorithmicScore,
} from "./scoring";

describe("scoring", () => {
  test("PHASE1_AI_GATE equals 50", () => {
    expect(PHASE1_AI_GATE).toBe(50);
  });

  test("passesPhase1Gate(49) returns false", () => {
    expect(passesPhase1Gate(49)).toBe(false);
  });

  test("passesPhase1Gate(50) returns true", () => {
    expect(passesPhase1Gate(50)).toBe(true);
  });

  test("WEIGHTS values sum to exactly 100", () => {
    const sum = Object.values(WEIGHTS).reduce((a, b) => a + b, 0);
    expect(sum).toBe(100);
  });

  test("computeAlgorithmicScore with perfect-match input produces total >= 80", () => {
    const perfectInput = {
      titleRelevance: 1,
      skillsMatch: 1,
      experienceMatch: 1,
      locationMatch: 1,
      industryMatch: 1,
    };
    const score = computeAlgorithmicScore(perfectInput);
    expect(score).toBeGreaterThanOrEqual(80);
  });
});

